/*!
 * gameMechanic.js — Compiled output of Card/GameMechanic/*.ts
 *
 * DO NOT EDIT THIS FILE BY HAND.
 *   Regenerate after editing .ts sources:
 *       npm run build:mechanic
 *
 * Architecture (data-driven):
 *   - GM.Mechanics[id].apply(ctx, params)  ← verbs (SelfHealing, ManaGain, ...)
 *   - GM.Conditions[id](ctx, cond)         ← predicates for prophecies
 *   - GM.Cards[name].effects               ← list { mechanic, params } per card
 *   - GM.TurnStartEffects[id](ctx)         ← passives ticking each turn
 *   - GM.applyEffects(effects, ctx)        ← engine helper, used by runtime
 *   - GM.evaluateCondition(cond, ctx)      ← engine helper
 *   - GM.makeContext(state, selfIdx, log)  ← engine helper
 */
var GM;
(function (GM) {
  "use strict";

  /* =============================================================== */
  /*  Registry                                                       */
  /* =============================================================== */
  GM.Mechanics        = {};
  GM.Conditions       = {};
  GM.Cards            = {};
  GM.TurnStartEffects = {};

  GM.applyEffects = function (effects, ctx) {
    for (var i = 0; i < effects.length; i++) {
      var e = effects[i];
      var mech = GM.Mechanics[e.mechanic];
      if (!mech) { ctx.log("proph", '(Không có mechanic "' + e.mechanic + '")'); continue; }
      try { mech.apply(ctx, e.params); }
      catch (err) {
        var msg = (err && err.message) ? err.message : String(err);
        ctx.log("proph", '(Lỗi mechanic "' + e.mechanic + '": ' + msg + ")");
      }
    }
  };

  GM.evaluateCondition = function (cond, ctx) {
    var fn = GM.Conditions[cond.type];
    if (!fn) { ctx.log("proph", '(Không có condition "' + cond.type + '")'); return false; }
    return fn(ctx, cond);
  };

  GM.makeContext = function (state, selfIdx, log) {
    var oppIdx = selfIdx === 0 ? 1 : 0;
    return {
      selfIdx: selfIdx, oppIdx: oppIdx,
      self: state.players[selfIdx], opp: state.players[oppIdx],
      players: state.players, state: state, log: log,
    };
  };

  /* =============================================================== */
  /*  Mechanics                                                      */
  /* =============================================================== */

  // --- SelfDamage ---
  GM.Mechanics["SelfDamage"] = { apply: function (ctx, params) {
    var me = ctx.self;
    if (!Number.isFinite(params.amount) || params.amount <= 0) return;
    var before = me.hp;
    var actual = Math.min(Math.floor(params.amount), before);
    me.hp = before - actual;
    if (actual > 0) ctx.log("cost", "   ↪ " + me.name + " mất " + actual + " HP → " + me.hp + "/" + me.maxHp);
  }};

  // --- SelfHealing ---
  GM.Mechanics["SelfHealing"] = { apply: function (ctx, params) {
    var me = ctx.self;
    var requested, label;
    if ("flat" in params) {
      if (!Number.isFinite(params.flat) || params.flat <= 0) return;
      requested = Math.floor(params.flat);
      label = "+" + requested;
    } else {
      if (!Number.isFinite(params.pctOfMax) || params.pctOfMax <= 0) return;
      requested = Math.max(1, Math.floor(me.maxHp * params.pctOfMax));
      label = "+" + requested + " (" + Math.round(params.pctOfMax * 100) + "% maxHp)";
    }
    var missing = me.maxHp - me.hp;
    if (missing <= 0) return;
    var actual = Math.min(requested, missing);
    me.hp += actual;
    ctx.log("effect", "   ↪ " + me.name + " hồi " + actual + " HP " + label + " → " + me.hp + "/" + me.maxHp);
  }};

  // --- OpponentDamage ---
  GM.Mechanics["OpponentDamage"] = { apply: function (ctx, params) {
    var t = ctx.opp;
    if (!Number.isFinite(params.amount) || params.amount <= 0) return;
    var before = t.hp;
    var actual = Math.min(Math.floor(params.amount), before);
    t.hp = before - actual;
    if (actual > 0) ctx.log("effect", "   ↪ " + t.name + " mất " + actual + " HP → " + t.hp + "/" + t.maxHp);
  }};

  // --- OpponentHealing ---
  GM.Mechanics["OpponentHealing"] = { apply: function (ctx, params) {
    var t = ctx.opp;
    var requested;
    if ("flat" in params) {
      if (!Number.isFinite(params.flat) || params.flat <= 0) return;
      requested = Math.floor(params.flat);
    } else {
      if (!Number.isFinite(params.pctOfMax) || params.pctOfMax <= 0) return;
      requested = Math.max(1, Math.floor(t.maxHp * params.pctOfMax));
    }
    var missing = t.maxHp - t.hp;
    if (missing <= 0) return;
    var actual = Math.min(requested, missing);
    t.hp += actual;
    ctx.log("effect", "   ↪ " + t.name + " hồi " + actual + " HP → " + t.hp + "/" + t.maxHp);
  }};

  // --- ManaGain ---
  GM.Mechanics["ManaGain"] = { apply: function (ctx, params) {
    var me = ctx.self;
    if (!Number.isFinite(params.amount) || params.amount <= 0) return;
    var safe = Math.floor(params.amount);
    me.mana += safe;
    ctx.log("effect", "   ↪ " + me.name + " +" + safe + " mana → " + me.mana.toLocaleString());
  }};

  // --- OpponentManaLoss ---
  GM.Mechanics["OpponentManaLoss"] = { apply: function (ctx, params) {
    var t = ctx.opp;
    if (!Number.isFinite(params.amount) || params.amount <= 0) return;
    var safe = Math.floor(params.amount);
    var before = t.mana;
    t.mana = Math.max(0, before - safe);
    var actual = before - t.mana;
    ctx.log("effect", "   ↪ " + t.name + " mất " + actual + " mana → " + t.mana.toLocaleString());
  }};

  // --- PlaceTree ---
  GM.Mechanics["PlaceTree"] = { apply: function (ctx, _params) {
    var me = ctx.self;
    me.trees += 1;
    ctx.log("effect", "   ↪ Đặt 1 🌳 vào ô linh vật của " + me.name + " (tổng " + me.trees + ")");
  }};

  // --- AddProphecy ---
  GM.Mechanics["AddProphecy"] = { apply: function (ctx, params) {
    var opp = ctx.opp;
    opp.incomingProphecies.push({
      owner:        ctx.selfIdx,
      label:        params.label,
      condition:    params.condition,
      thenEffects:  params.thenEffects,
      elseEffects:  params.elseEffects || [],
    });
    ctx.log("proph",
      '   ↪ Đặt lời tiên tri "' + params.label + '" lên ' + opp.name +
      " (resolve cuối lượt sau của " + opp.name + ")");
  }};

  /* =============================================================== */
  /*  Conditions                                                     */
  /* =============================================================== */
  GM.Conditions["OpponentPlayedAtLeast"] = function (ctx, cond) {
    return ctx.state.cardsThisTurn >= cond.count;
  };
  GM.Conditions["OpponentPlayedAtMost"] = function (ctx, cond) {
    return ctx.state.cardsThisTurn <= cond.count;
  };

  /* =============================================================== */
  /*  Passives                                                       */
  /* =============================================================== */
  var TREE_HEAL_PCT = 0.05;
  GM.TurnStartEffects["tree"] = function (ctx) {
    var me = ctx.self;
    if (me.trees <= 0) return;
    var perTree   = Math.max(1, Math.floor(me.maxHp * TREE_HEAL_PCT));
    var requested = perTree * me.trees;
    GM.Mechanics["SelfHealing"].apply(ctx, { flat: requested });
  };

  /* =============================================================== */
  /*  Card definitions                                               */
  /* =============================================================== */

  GM.Cards["Tiên tri hủy diệt"] = {
    effects: [{
      mechanic: "AddProphecy",
      params: {
        label: "Hủy diệt",
        condition: { type: "OpponentPlayedAtLeast", count: 1 },
        thenEffects: [{ mechanic: "SelfHealing", params: { flat: 8 } }],
        elseEffects: [],
      },
    }],
  };

  GM.Cards["Tiên tri hòa bình"] = {
    effects: [{
      mechanic: "AddProphecy",
      params: {
        label: "Hòa bình",
        condition: { type: "OpponentPlayedAtMost", count: 0 },
        thenEffects: [{ mechanic: "ManaGain", params: { amount: 8 } }],
        elseEffects: [],
      },
    }],
  };

  GM.Cards["Cây cổ thụ"] = {
    effects: [{ mechanic: "PlaceTree", params: {} }],
  };
})(GM || (GM = {}));

/* =============================================================== */
/*  Init — expose GM globally                                      */
/* =============================================================== */
(function () {
  var g = typeof globalThis !== "undefined" ? globalThis : this;
  g.GM = GM;
})();
